const fs = require('fs');
const path = require('path');

const root = path.resolve(__dirname, '..');
const seoDir = path.join(root, 'seo-pages');
const sitemapPath = path.join(root, 'sitemap.xml');
const today = new Date().toISOString().slice(0, 10);
const ctaUrl = '/?signup=true&role=client';

function esc(v) {
  return String(v || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function slugTitle(slug) {
  const upper = { itr: 'ITR', gst: 'GST', tds: 'TDS', esi: 'ESI', pf: 'PF', epf: 'EPF', llp: 'LLP', opc: 'OPC', roc: 'ROC', din: 'DIN', kyc: 'KYC', gstr: 'GSTR', itc: 'ITC', hra: 'HRA', ais: 'AIS', tcs: 'TCS', cfo: 'CFO', msme: 'MSME', udyam: 'Udyam', nris: 'NRIs', crypto: 'Crypto' };
  return slug.split('-').map(p => upper[p] || p.charAt(0).toUpperCase() + p.slice(1)).join(' ');
}

function list(items) {
  return `<ul class="wi-detail-list">${items.map(item => `<li>${item}</li>`).join('')}</ul>`;
}

function steps(items) {
  return `<div class="lp-steps">${items.map(item => `<div class="lp-step"><h3>${esc(item.title)}</h3><p>${item.body}</p></div>`).join('')}</div>`;
}

function table(headers, rows) {
  return `<table class="wi-table"><thead><tr>${headers.map(h => `<th>${esc(h)}</th>`).join('')}</tr></thead><tbody>${rows.map(row => `<tr>${row.map(cell => `<td>${cell}</td>`).join('')}</tr>`).join('')}</tbody></table>`;
}

function linkList(items) {
  return items.map(item => `<a href="/seo-pages/${item}.html">${esc(slugTitle(item))}</a>`).join('');
}

