function schema(page) {
  const url = `https://workindex.co.in/seo-pages/${page.slug}.html`;
  const graph = [
    { '@type': 'Organization', '@id': 'https://workindex.co.in/#organization', name: 'WorkIndex', url: 'https://workindex.co.in', description: 'India-focused marketplace to hire verified finance, tax, GST, accounting, compliance and web development experts.' },
    { '@type': 'WebPage', '@id': `${url}#webpage`, url, name: page.title, description: page.meta, about: { '@id': 'https://workindex.co.in/#organization' } },
    { '@type': page.type === 'Blog' ? 'Article' : page.type === 'Calculator' ? 'SoftwareApplication' : 'Service', name: page.h1, serviceType: page.service || page.h1, headline: page.h1, description: page.meta, provider: { '@id': 'https://workindex.co.in/#organization' }, areaServed: page.area || { '@type': 'Country', name: 'India' } },
    { '@type': 'BreadcrumbList', itemListElement: [{ '@type': 'ListItem', position: 1, name: 'WorkIndex', item: 'https://workindex.co.in' }, { '@type': 'ListItem', position: 2, name: page.h1, item: url }] },
    { '@type': 'FAQPage', mainEntity: page.faqs.map(f => ({ '@type': 'Question', name: f.q, acceptedAnswer: { '@type': 'Answer', text: f.a.replace(/<[^>]+>/g, '') } })) }
  ];
  return JSON.stringify({ '@context': 'https://schema.org', '@graph': graph });
}

function calculatorBlock(kind) {
  if (kind === 'tds') return `<section class="wi-panel"><div class="lp-section-eyebrow">Calculator</div><h2>TDS estimate by payment type</h2><div class="wi-calc-grid"><label>Payment type<select id="tdsType"><option value="salary">Salary - estimate slab TDS</option><option value="professional">Professional fees - 194J</option><option value="contractor-individual">Contractor individual/HUF - 194C</option><option value="contractor-company">Contractor other than individual/HUF - 194C</option><option value="rent-business">Rent by business - 194I</option><option value="rent-individual">Rent by individual/HUF above Rs. 50,000/month - 194IB</option><option value="commission">Commission or brokerage - 194H</option><option value="interest">Interest other than securities - 194A</option><option value="vda">Virtual digital asset transfer - 194S</option></select></label><label>Payment amount<input id="tdsAmount" type="number" value="100000"></label><label>PAN status<select id="panStatus"><option value="yes">Valid PAN available</option><option value="no">No PAN / invalid PAN</option></select></label></div><button class="lp-hero-cta" type="button" onclick="calcTds()">Calculate TDS</button><div id="tdsResult" class="calc-result"></div><p class="wi-note">This is an estimate for common resident-payment cases. Thresholds, lower deduction certificates, salary slab computation and special payees can change the final answer.</p></section><script>function calcTds(){const type=document.getElementById('tdsType').value;const amount=+document.getElementById('tdsAmount').value||0;const pan=document.getElementById('panStatus').value;const rates={salary:10,professional:10,'contractor-individual':1,'contractor-company':2,'rent-business':10,'rent-individual':2,commission:2,interest:10,vda:1};let rate=rates[type]||10;if(pan==='no') rate=Math.max(20, rate*2);const tds=Math.round(amount*rate/100);document.getElementById('tdsResult').innerHTML='<b>Applicable estimate:</b> '+rate+'%<br><b>TDS:</b> Rs. '+tds.toLocaleString('en-IN')+'<br><b>Net payable:</b> Rs. '+Math.max(0,amount-tds).toLocaleString('en-IN');}calcTds();</script>`;
  if (kind === 'advance') return `<section class="wi-panel"><div class="lp-section-eyebrow">Calculator</div><h2>Advance tax instalment estimate</h2><div class="wi-calc-grid"><label>Estimated annual gross income<input id="annualIncome" type="number" value="1200000"></label><label>Deductions/exemptions to reduce taxable income<input id="deductions" type="number" value="150000"></label><label>Tax regime<select id="taxRegime"><option value="new">New regime estimate</option><option value="old">Old regime estimate</option></select></label><label>TDS/TCS already deducted or expected<input id="tdsPaid" type="number" value="30000"></label><label>Advance tax already paid<input id="advPaid" type="number" value="0"></label></div><button class="lp-hero-cta" type="button" onclick="calcAdvance()">Calculate</button><div id="advanceResult" class="calc-result"></div><p class="wi-note">This calculator uses common individual slab estimates and 4% cess. Surcharge, marginal relief, special-rate income, capital gains and business losses need professional review.</p></section><script>function slabTax(income,regime){let slabs=regime==='new'?[ [400000,0],[800000,.05],[1200000,.10],[1600000,.15],[2000000,.20],[2400000,.25],[Infinity,.30] ]:[ [250000,0],[500000,.05],[1000000,.20],[Infinity,.30] ];let tax=0,prev=0;for(const [limit,rate] of slabs){if(income>prev){tax+=(Math.min(income,limit)-prev)*rate;prev=limit;}if(income<=limit)break;}if(regime==='new'&&income<=1200000)tax=0;if(regime==='old'&&income<=500000)tax=0;return Math.round(tax*1.04);}function calcAdvance(){const income=+document.getElementById('annualIncome').value||0,ded=+document.getElementById('deductions').value||0,regime=document.getElementById('taxRegime').value,tds=+document.getElementById('tdsPaid').value||0,paid=+document.getElementById('advPaid').value||0;const taxable=Math.max(0,income-ded);const tax=slabTax(taxable,regime);const net=Math.max(0,tax-tds);const rows=[['15 June','15%',.15],['15 September','45%',.45],['15 December','75%',.75],['15 March','100%',1]].map(r=>'<tr><td>'+r[0]+'</td><td>'+r[1]+'</td><td>Rs. '+Math.max(0,Math.round(net*r[2]-paid)).toLocaleString('en-IN')+'</td></tr>').join('');document.getElementById('advanceResult').innerHTML='<b>Taxable income estimate:</b> Rs. '+taxable.toLocaleString('en-IN')+'<br><b>Total tax estimate with cess:</b> Rs. '+tax.toLocaleString('en-IN')+'<br><b>Net advance tax after TDS/TCS:</b> Rs. '+net.toLocaleString('en-IN')+'<table class=\"wi-table\"><tr><th>Due date</th><th>Cumulative %</th><th>Balance to meet cumulative target</th></tr>'+rows+'</table>';}calcAdvance();</script>`;
  if (kind === 'hra') return `<section class="wi-panel"><div class="lp-section-eyebrow">Calculator</div><h2>HRA exemption calculator</h2><div class="wi-calc-grid"><label>Basic salary per month<input id="basic" type="number" value="50000"></label><label>HRA received per month<input id="hra" type="number" value="20000"></label><label>Rent paid per month<input id="rent" type="number" value="18000"></label><label>City type<select id="cityType"><option value="metro">Metro - Delhi, Mumbai, Chennai, Kolkata</option><option value="nonmetro">Non-metro</option></select></label></div><button class="lp-hero-cta" type="button" onclick="calcHra()">Calculate HRA</button><div id="hraResult" class="calc-result"></div></section><script>function calcHra(){const basic=(+document.getElementById('basic').value||0)*12,hra=(+document.getElementById('hra').value||0)*12,rent=(+document.getElementById('rent').value||0)*12,metro=document.getElementById('cityType').value==='metro';const c1=hra,c2=Math.max(0,rent-basic*.10),c3=basic*(metro?.5:.4);const exempt=Math.min(c1,c2,c3);document.getElementById('hraResult').innerHTML='<b>Exempt HRA:</b> Rs. '+Math.round(exempt).toLocaleString('en-IN')+'<br>Actual HRA: Rs. '+Math.round(c1).toLocaleString('en-IN')+'<br>Rent minus 10% basic: Rs. '+Math.round(c2).toLocaleString('en-IN')+'<br>'+(metro?'50%':'40%')+' of basic: Rs. '+Math.round(c3).toLocaleString('en-IN')+'<br><b>Taxable HRA:</b> Rs. '+Math.max(0,Math.round(hra-exempt)).toLocaleString('en-IN');}calcHra();</script>`;
  if (kind === 'tdsLate') return `<section class="wi-panel"><div class="lp-section-eyebrow">Calculator</div><h2>Section 234E late fee estimate</h2><div class="wi-calc-grid"><label>Due date<input id="dueDate" type="date" value="2026-07-31"></label><label>Actual filing date<input id="fileDate" type="date" value="2026-08-15"></label><label>Total TDS deducted in quarter<input id="quarterTds" type="number" value="25000"></label><label>Form type<select><option>24Q</option><option>26Q</option><option>27EQ</option></select></label></div><button class="lp-hero-cta" type="button" onclick="calcTdsLate()">Calculate late fee</button><div id="tdsLateResult" class="calc-result"></div></section><script>function calcTdsLate(){const due=new Date(document.getElementById('dueDate').value),file=new Date(document.getElementById('fileDate').value),tds=+document.getElementById('quarterTds').value||0;const days=Math.max(0,Math.ceil((file-due)/(24*60*60*1000)));const fee=Math.min(days*200,tds);document.getElementById('tdsLateResult').innerHTML='<b>Days delayed:</b> '+days+'<br><b>Late fee u/s 234E:</b> Rs. '+fee.toLocaleString('en-IN')+'<br><span>Formula: Rs. 200 per day, capped at total TDS for that return.</span>';}calcTdsLate();</script>`;
  return '';
}

function render(page) {
  const canonical = `https://workindex.co.in/seo-pages/${page.slug}.html`;
  const refs = page.refs || officialRefs.slice(0, 5);
  const related = page.related || relatedDefault;
  const accuracyNotes = [
    `For ${page.h1}, the numbers and eligibility should be checked against the latest portal records before filing or paying. Indian compliance rules often depend on financial year, assessment year, turnover, residential status, deductor type, GST registration type, employee count, city, documentation quality and whether a notice has already been issued.`,
    `Use this page as a preparation guide, then share exact facts with a professional: dates, amounts, sections/forms, portal screenshots, prior filings, challans, notices and supporting documents. A good WorkIndex response should mention what the expert will verify, what is included in the fee, expected turnaround time and what follow-up is excluded.`,
    `Where rates or thresholds are shown, they are intended for common cases and should not replace professional review. Lower deduction certificates, exemptions, special payees, reverse charge, composition scheme, foreign income, capital gains timing, payroll thresholds or old-year corrections can change the final treatment.`
  ];
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width, initial-scale=1.0"/>
<title>${esc(page.title)}</title><meta name="description" content="${esc(page.meta)}"/><meta name="keywords" content="${esc((page.keywords || []).join(', '))}"/>
<link rel="canonical" href="${canonical}"/><meta property="og:title" content="${esc(page.title)}"/><meta property="og:description" content="${esc(page.meta)}"/><meta property="og:url" content="${canonical}"/><meta property="og:type" content="website"/>
<link rel="icon" type="image/png" href="/favicon.png"/><link rel="stylesheet" href="/lp-styles.css"/>
<style>.wi-rich{padding:56px 24px;max-width:1160px;margin:0 auto}.wi-rich-grid{display:grid;grid-template-columns:minmax(0,1.35fr) minmax(280px,.65fr);gap:28px;align-items:start}.wi-panel{background:#fff;border:1.5px solid var(--border);border-radius:16px;padding:28px;box-shadow:var(--shadow)}.wi-panel+.wi-panel{margin-top:20px}.wi-panel h2{font-size:24px;margin:0 0 14px}.wi-panel h3{font-size:17px;margin:18px 0 8px}.wi-panel p{color:var(--text-muted);font-size:15px;margin:0 0 12px;line-height:1.75}.wi-detail-list{margin:10px 0 0 18px;color:var(--text-muted);font-size:15px;line-height:1.75}.wi-detail-list li{margin-bottom:7px}.wi-side{position:sticky;top:82px}.wi-table{width:100%;border-collapse:collapse;margin-top:12px;font-size:14px}.wi-table th,.wi-table td{border:1px solid var(--border);padding:11px;text-align:left;vertical-align:top}.wi-table th{background:var(--bg-gray);font-weight:800}.wi-ref a,.wi-related a{display:block;color:var(--primary);font-weight:800;text-decoration:none;margin:8px 0}.wi-note,.calc-result{border-left:4px solid var(--primary);background:var(--primary-light);padding:16px;border-radius:12px;color:var(--text);line-height:1.7;margin-top:14px}.wi-calc-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:14px}.wi-calc-grid input,.wi-calc-grid select{width:100%;padding:12px;border:1px solid #d1d5db;border-radius:10px;margin-top:6px}.formula{font-family:monospace;background:#0f172a;color:#fff;padding:14px;border-radius:10px;overflow:auto}@media(max-width:860px){.wi-rich-grid{grid-template-columns:1fr}.wi-side{position:static}}</style>
<script type="application/ld+json">${schema(page)}</script><script async src="https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=ca-pub-2627739469695660" crossorigin="anonymous"></script><meta name="google-adsense-account" content="ca-pub-2627739469695660"></head>
<body><nav class="lp-nav"><a href="/" class="lp-nav-logo"><div class="lp-nav-logo-icon">W</div><span class="lp-nav-logo-text">WorkIndex</span></a><a href="${ctaUrl}" class="lp-nav-cta">Post for Free</a></nav>
<div class="lp-breadcrumb"><a href="/">WorkIndex</a><span>/</span><span>${esc(page.h1)}</span></div>
<section class="lp-hero"><div class="lp-hero-eyebrow"><div class="lp-hero-eyebrow-dot"></div>${esc(page.type)}</div><h1>${esc(page.h1)}<br><span>${esc(page.subtitle)}</span></h1><p>${page.hero}</p><a href="${ctaUrl}" class="lp-hero-cta">Post Your Requirement - Free</a><div class="lp-hero-trust"><div class="lp-trust-item">Verified expert discovery</div><div class="lp-trust-item">Compare quotes and timelines</div><div class="lp-trust-item">India-specific guidance</div><div class="lp-trust-item">Structured requirements</div></div></section>
<main class="wi-rich"><div class="wi-rich-grid"><div>${calculatorBlock(page.calculator || '')}${page.sections.map(s => `<section class="wi-panel"><div class="lp-section-eyebrow">${esc(s.eyebrow || page.type)}</div><h2>${esc(s.title)}</h2>${s.html || (s.items ? list(s.items) : s.steps ? steps(s.steps) : s.table ? table(s.table.headers, s.table.rows) : `<p>${s.body}</p>`)}</section>`).join('')}
<section class="wi-panel"><div class="lp-section-eyebrow">Official Accuracy Notes</div><h2>How to use this page safely</h2>${accuracyNotes.map(n => `<p>${esc(n)}</p>`).join('')}</section>
<section class="wi-panel"><div class="lp-section-eyebrow">Expert Screening</div><h2>How to compare responses on WorkIndex</h2>${list(['Ask the expert to confirm the exact law, form, return, portal workflow or calculation method before starting.', 'Check whether the quote includes only filing/calculation or also reconciliation, response drafting, correction filing and follow-up.', 'Prefer professionals who ask for records first instead of quoting blindly from the page title.', 'For urgent matters, mention deadline, notice date, due date, penalty exposure and whether portal access is already available.', 'After completion, keep acknowledgement, computation, challan, certificate, response copy and working papers in one folder.'])}</section>
<section class="wi-panel"><div class="lp-section-eyebrow">Records Checklist</div><h2>Keep these ready before requesting quotes</h2>${list(['PAN, Aadhaar, GSTIN, TAN, CIN/LLPIN, UAN or DIN as applicable to the topic.', 'Income Tax, GST, MCA, EPFO/ESIC or Udyam portal login access where required.', 'Previous filings, acknowledgements, challans, certificates, notices, orders and correction history.', 'Bank statements, invoices, salary records, rent agreements, capital gain reports, payroll data or accounting exports relevant to the case.', 'A short note explaining what happened, what deadline exists, what result you want and whether you need online or local support.'])}</section>
<section class="wi-panel"><div class="lp-section-eyebrow">Questions People Ask</div><h2>FAQs</h2>${page.faqs.map(f => `<h3>${esc(f.q)}</h3><p>${f.a}</p>`).join('')}</section></div>
<aside class="wi-side"><div class="wi-panel"><h2>Post once, compare experts</h2><p>${page.side || 'Share your requirement once and compare relevant WorkIndex experts by scope, price, timeline and profile strength.'}</p><a href="${ctaUrl}" class="lp-hero-cta" style="padding:12px 18px;font-size:14px">Get Expert Quotes</a></div><div class="wi-panel wi-related"><h2>Related pages</h2>${linkList(related)}</div><div class="wi-panel wi-ref"><h2>Official references</h2>${refs.map(r => `<a href="${r.href}" rel="nofollow">${esc(r.label)}</a>`).join('')}</div></aside></div></main>
<section class="lp-cta-section"><h2>Need a professional to review your case?</h2><p>Post your requirement on WorkIndex and compare experts before hiring.</p><a href="${ctaUrl}" class="lp-hero-cta">Post Requirement as Customer</a></section>
<footer class="lp-footer"><a href="/seo-pages/itr-filing-all-cities.html">ITR cities</a><a href="/seo-pages/gst-services-all-cities.html">GST cities</a><a href="/seo-pages/accounting-services-all-cities.html">Accounting cities</a><a href="/seo-pages/audit-services-all-cities.html">Audit cities</a><a href="/contact.html">Contact</a></footer></body></html>`;
}

function page(slug, type, title, meta, h1, subtitle, hero, sections, faqs, related, extra = {}) {
  return { slug, type, title, meta, h1, subtitle, hero, sections, faqs, related, keywords: extra.keywords || [h1, title, 'WorkIndex'], calculator: extra.calculator, service: extra.service, area: extra.area, refs: extra.refs, side: extra.side };
}

