const overwrite = process.argv.includes('--overwrite');
for (const p of pages) {
  const file = path.join(seoDir, `${p.slug}.html`);
  if (fs.existsSync(file) && !overwrite) continue;
  fs.writeFileSync(file, render(p));
  created.push(`seo-pages/${p.slug}.html`);
}

let sitemap = fs.readFileSync(sitemapPath, 'utf8');
for (const p of pages) {
  const loc = `https://workindex.co.in/seo-pages/${p.slug}.html`;
  if (!sitemap.includes(loc)) {
    sitemap = sitemap.replace('</urlset>', `  <url><loc>${loc}</loc><priority>0.74</priority><changefreq>monthly</changefreq><lastmod>${today}</lastmod></url>\n</urlset>`);
  }
}
fs.writeFileSync(sitemapPath, sitemap);

